mapper.select:
SELECT 
FROM toy_consultation
WHERE user_id = #{userId}

    AND status = #{status}

ORDER BY updated_at DESC, id DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1)
FROM toy_consultation
WHERE user_id = #{userId}

    AND status = #{status}

SELECT c.id, c.user_id, c.product_id, c.seller_id, c.status, c.last_message, c.last_sender_type,
       c.unread_user_count, c.unread_admin_count, c.created_at, c.updated_at, c.closed_at
FROM toy_consultation c
LEFT JOIN sys_user u ON c.user_id = u.id
LEFT JOIN product p ON c.product_id = p.id
WHERE 1 = 1

    AND (
        u.username LIKE CONCAT('%', #{keyword}, '%')
        OR p.name LIKE CONCAT('%', #{keyword}, '%')
        OR c.last_message LIKE CONCAT('%', #{keyword}, '%')
    )


    AND c.user_id = #{userId}


    AND c.product_id = #{productId}


    AND c.status = #{status}

ORDER BY c.updated_at DESC, c.id DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1)
FROM toy_consultation c
LEFT JOIN sys_user u ON c.user_id = u.id
LEFT JOIN product p ON c.product_id = p.id
WHERE 1 = 1

    AND (
        u.username LIKE CONCAT('%', #{keyword}, '%')
        OR p.name LIKE CONCAT('%', #{keyword}, '%')
        OR c.last_message LIKE CONCAT('%', #{keyword}, '%')
    )


    AND c.user_id = #{userId}


    AND c.product_id = #{productId}


    AND c.status = #{status}

